-- Safely align the 17 Issue #178 fishing spot master rows.
-- Data-only upsert for the scoped Issue #178 master rows.
-- Remote Supabase is not directly modified by this migration file.

on conflict (id) do update set
  name = excluded.name,
  area_name = excluded.area_name,
  latitude = excluded.latitude,
  longitude = excluded.longitude,
  spot_type = excluded.spot_type,
  shore_access = excluded.shore_access,
  coordinate_precision = excluded.coordinate_precision,
  target_species = excluded.target_species,
  recommended_methods = excluded.recommended_methods,
  notes = excluded.notes,
  is_active = excluded.is_active,
  updated_at = now();
